import React, { useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const Dashboard = () => {
  const navigate = useNavigate();

  useEffect(() => {
    // Check if token exists on load
    const token = localStorage.getItem('token');
    if (!token) {
      navigate('/login'); // Redirect if not logged in
    }
  }, [navigate]);

  const handleLogout = () => {
    // 1. Remove the token
    localStorage.removeItem('token');
    
    // 2. Redirect to login
    navigate('/login');
  };

  return (
    <div className="dashboard-wrapper">
      <nav style={{ display: 'flex', justifyContent: 'space-between', padding: '1rem', background: '#f4f4f4' }}>
        <h1>StudyPulse Dashboard</h1>
        <button 
          onClick={handleLogout}
          style={{ backgroundColor: '#ff4b4b', color: 'white', border: 'none', padding: '10px 20px', cursor: 'pointer' }}
        >
          Logout
        </button>
      </nav>

      <div className="content">
        <h3>Welcome back!</h3>
        <p>Your study sessions and tasks will appear here.</p>
        {/* Your StudyRoom and Task logic goes here */}
      </div>
    </div>
  );
};

export default Dashboard;
